export const preferredPaymentMethods = ['credit_card', 'wire_transfer', 'ach', 'paypal'];

export async function ensureSchema(client) {
	// ─── accounts ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS accounts (
			account_id TEXT PRIMARY KEY,
			name TEXT NOT NULL,
			tier TEXT NOT NULL,
			CONSTRAINT chk_accounts_tier CHECK (tier IN ('strategic', 'enterprise', 'midmarket', 'standard')),
			segment TEXT,
			region TEXT,
			status TEXT NOT NULL,
			CONSTRAINT chk_accounts_status CHECK (status IN ('active', 'at-risk', 'churned', 'prospect')),
			created_at TIMESTAMPTZ NOT NULL,
			preferred_payment_method TEXT,
			CONSTRAINT chk_accounts_preferred_payment_method CHECK (preferred_payment_method IN ('credit_card', 'wire_transfer', 'ach', 'paypal'))
	)`);
	await client.query(`ALTER TABLE accounts ADD COLUMN IF NOT EXISTS preferred_payment_method TEXT`);

